import type { CSSProperties, ReactNode } from 'react';
import { useSession } from './useSession';

export interface SignInButtonProps {
  /**
   * Button label. Default: "Sign in with Kannegiesser SSO".
   * Ignored when `children` is provided.
   */
  label?: string;
  /**
   * Extra className appended after the built-in one. Use this to add
   * Tailwind modifiers, spacing, or override width in your app's styling.
   */
  className?: string;
  /**
   * Inline style overrides. Merged on top of the default style object,
   * so any key here wins (e.g. `{backgroundColor: '#000'}`).
   */
  style?: CSSProperties;
  /**
   * If provided, renders these contents instead of the default
   * icon + label. Useful for custom layouts.
   */
  children?: ReactNode;
  /**
   * Optional returnTo URL forwarded to the broker's /auth/login endpoint.
   * Defaults to the current page (handled by the SDK).
   */
  returnTo?: string;
  /**
   * Hide the lock icon. Default: false.
   */
  hideIcon?: boolean;
  /**
   * Optional `aria-label` override. Defaults to the resolved label.
   */
  ariaLabel?: string;
}

const BRAND_DARK = '#275DA1';

/**
 * Default style uses inline CSS so the button looks correct in any app,
 * regardless of Tailwind / styled-components / plain CSS. Apps can override
 * with `className` or `style`.
 */
const defaultStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: '0.625rem',
  width: '100%',
  padding: '0.75rem 1rem',
  backgroundColor: BRAND_DARK,
  color: '#FFFFFF',
  fontWeight: 500,
  fontSize: '1rem',
  lineHeight: 1.25,
  fontFamily: 'inherit',
  border: 'none',
  borderRadius: '0.5rem',
  cursor: 'pointer',
  transition: 'background-color 0.15s ease, filter 0.15s ease',
};

/**
 * Branded "Sign in with Kannegiesser SSO" button. Click handler calls
 * `login(returnTo)` from `useSession`, so this component must be rendered
 * inside an `<SsoProvider>`.
 *
 * @example
 * import { useSession, SignInButton } from '@etechinc/sso-client';
 *
 * function Gate() {
 *   const { user, loading } = useSession();
 *   if (loading) return <Spinner />;
 *   if (!user) return <SignInButton />;
 *   return <App />;
 * }
 */
export function SignInButton(props: SignInButtonProps) {
  const { login } = useSession();
  const {
    label = 'Sign in with Kannegiesser SSO',
    className,
    style,
    children,
    returnTo,
    hideIcon = false,
    ariaLabel,
  } = props;

  return (
    <button
      type="button"
      aria-label={ariaLabel ?? label}
      onClick={() => login(returnTo)}
      className={className}
      style={{ ...defaultStyle, ...style }}
      onMouseEnter={(e) => {
        (e.currentTarget as HTMLButtonElement).style.filter = 'brightness(0.92)';
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLButtonElement).style.filter = '';
      }}
    >
      {children ?? (
        <>
          {!hideIcon && <LockIcon />}
          <span>{label}</span>
        </>
      )}
    </button>
  );
}

function LockIcon() {
  return (
    <svg
      width="18"
      height="18"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
      focusable="false"
      style={{ flexShrink: 0 }}
    >
      <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
      <path d="M7 11V7a5 5 0 0 1 10 0v4" />
    </svg>
  );
}
