export function redirectToLogin(
  brokerOrigin: string,
  returnTo: string = window.location.href,
): void {
  const url = new URL(`${brokerOrigin}/auth/login`);
  url.searchParams.set('returnTo', returnTo);
  window.location.assign(url.toString());
}

export function redirectToLogout(brokerOrigin: string): void {
  // Use form POST so credentials are included and the browser follows the 302
  // to Azure's end_session endpoint. A GET would not cause a navigation with
  // cookies in all browsers because the broker requires POST.
  const form = document.createElement('form');
  form.method = 'POST';
  form.action = `${brokerOrigin}/auth/logout`;
  form.style.display = 'none';
  document.body.appendChild(form);
  form.submit();
}
