import type { SessionUser } from '../types';

export async function fetchSession(brokerOrigin: string): Promise<SessionUser | null> {
  const res = await fetch(`${brokerOrigin}/auth/session`, { credentials: 'include' });
  if (res.status === 200) return (await res.json()) as SessionUser;
  return null;
}

export async function postRefresh(brokerOrigin: string): Promise<boolean> {
  const res = await fetch(`${brokerOrigin}/auth/refresh`, {
    method: 'POST',
    credentials: 'include',
  });
  return res.ok;
}

export async function postLogout(brokerOrigin: string): Promise<void> {
  await fetch(`${brokerOrigin}/auth/logout`, {
    method: 'POST',
    credentials: 'include',
    redirect: 'manual',
  });
}
