import {
  createContext,
  useCallback,
  useEffect,
  useRef,
  useState,
  type ReactNode,
} from 'react';
import type { SessionUser, SsoConfig } from '../types';
import { fetchSession, postRefresh } from './api';
import { redirectToLogin, redirectToLogout } from './redirect';

export interface SsoContextValue {
  user: SessionUser | null;
  loading: boolean;
  error: Error | null;
  login: (returnTo?: string) => void;
  logout: () => void;
  hasRole: (role: string) => boolean;
  refresh: () => Promise<void>;
  appSlug: string;
  brokerOrigin: string;
}

export const SsoContext = createContext<SsoContextValue | null>(null);

export function SsoProvider({
  children,
  brokerOrigin,
  appSlug,
}: SsoConfig & { children: ReactNode }) {
  const [user, setUser] = useState<SessionUser | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<Error | null>(null);
  const mounted = useRef(true);

  const load = useCallback(async () => {
    try {
      const s = await fetchSession(brokerOrigin);
      if (mounted.current) setUser(s);
    } catch (e) {
      if (mounted.current) setError(e as Error);
    } finally {
      if (mounted.current) setLoading(false);
    }
  }, [brokerOrigin]);

  useEffect(() => {
    mounted.current = true;
    void load();
    return () => {
      mounted.current = false;
    };
  }, [load]);

  // Silent refresh on window focus if JWT is near expiry
  useEffect(() => {
    function onFocus() {
      if (!user) return;
      const secondsLeft = user.expiresAt - Math.floor(Date.now() / 1000);
      if (secondsLeft < 60) {
        void postRefresh(brokerOrigin).then((ok) => (ok ? load() : setUser(null)));
      }
    }
    window.addEventListener('focus', onFocus);
    return () => window.removeEventListener('focus', onFocus);
  }, [user, brokerOrigin, load]);

  const value: SsoContextValue = {
    user,
    loading,
    error,
    appSlug,
    brokerOrigin,
    login: (returnTo?: string) => redirectToLogin(brokerOrigin, returnTo),
    logout: () => redirectToLogout(brokerOrigin),
    hasRole: (role) => !!user?.access[appSlug]?.includes(role),
    refresh: load,
  };

  return <SsoContext.Provider value={value}>{children}</SsoContext.Provider>;
}
